<script setup lang="ts">
definePageMeta({layout:'default'})
const supabase=useSupabaseClient<any>(),data=ref<any>(),busy=ref(false),error=ref(''),message=ref(''),obligations=ref('[{"id":"payable-1","amount":1000,"currency":"USD","due_at":"2026-08-01T12:00:00Z","penalty":50}]'),cash=ref(10000),reserve=ref(2500),adapterId=ref(''),snapshotId=ref('')
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(options.headers||{}),...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
async function load(){error.value='';try{data.value=await authed('/api/business/provider-intelligence/compounding');adapterId.value||=data.value.adapters?.[0]?.id||'';snapshotId.value||=data.value.authority_snapshots?.[0]?.id||''}catch(e:any){error.value=e?.data?.message||e?.message||'Provider sovereignty evidence is unavailable.'}}
async function act(url:string,body:any){busy.value=true;error.value='';message.value='';try{await authed(url,{method:'POST',body});message.value='Proof-carrying result recorded. Consequential actions remain on their approval rail.';await load()}catch(e:any){error.value=e?.data?.message||e?.message||'The governed operation failed.'}finally{busy.value=false}}
function treasury(){let parsed:any[];try{parsed=JSON.parse(obligations.value)}catch{error.value='Obligations must be valid JSON.';return}return act('/api/business/provider-intelligence/treasury-plan',{obligations:parsed,available_cash:cash.value,minimum_reserve:reserve.value,currency:'USD'})}
onMounted(load)
</script>
