asury graph optimizer</span><h2 class="mt-1 text-xl font-semibold">Schedule cash, preserve reserve</h2><textarea v-model="obligations" rows="7" class="mt-4 w-full rounded-lg border p-2 font-mono text-[9px]"/><div class="mt-2 grid grid-cols-2 gap-2"><input v-model.number="cash" type="number" class="rounded border p-2 text-xs" aria-label="Available cash"><input v-model.number="reserve" type="number" class="rounded border p-2 text-xs" aria-label="Minimum reserve"></div><button :disabled="busy" class="mt-3 w-full rounded bg-gray-950 p-2 text-xs text-white">Generate governed plan</button></form><article class="rounded-2xl border bg-white p-5"><span class="text-[9px] uppercase text-cyan-800">Adapter certification</span><h2 class="mt-1 text-xl font-semibold">Infer and model-check lifecycle</h2><select v-model="adapterId" class="mt-4 w-full rounded border p-2 text-xs"><option v-for="a in data?.adapters||[]" :key="a.id" :value="a.id">{{a.provider}} · {{a.version}}</option></select><button :disabled="busy||!adapterId" class="mt-3 w-full rounded bg-gray-950 p-2 text-xs text-white" @click="act('/api/business/provider-intelligence/state-machine',{adapter_id:adapterId,traces:[]})">Certify state machine</button><div v-for="m in data?.state_machines?.slice(0,4)||[]" :key="m.id" class="mt-3 rounded-lg bg-gray-50 p-3 text-[9px]"><b>{{m.operation}}</b><p class="mt-1 text-gray-500">{{m.status}} · {{Math.round(m.coverage*100)}}% evidence coverage</p></div></article><article class="rounded-2xl border bg-white p-5"><span class="text-[9px] uppercase text-cyan-800">Regulatory impact twin</span><h2 class="mt-1 text-xl font-semibold">Find every affected record</h2><select v-model="snapshotId" class="mt-4 w-full rounded border p-2 text-xs"><option v-for="s in data?.authority_snapshots||[]" :key="s.id" :value="s.id">{{s.content_digest.slice(0,12)}} · {{s.effective_at}}</option></select><button :disabled="busy||!snapshotId" class="mt-3 w-full rounded bg-gray-950 p-2 text-xs text-white" @click="act('/api/business/provider-intelligence/regulatory-impact',{snapshot_id:snapshotId})">Run impact simulation</button><div v-for="x in data?.regulatory_impacts?.slice(0,5)||[]" :key="x.id" class="mt-3 rounded-lg bg-amber-50 p-3 text-[9px] text-amber-800"><b>{{x.impact_count}} affected records</b><p class="mt-1">Professional review required</p></div></article></section><section class="grid gap-5 lg:grid-cols-2"><article class="rounded-2xl border bg-white p-5"><span class="text-[9px] uppercase text-cyan-800">Semantic finality</span><h2 class="mt-1 text-xl font-semibold">One obligation, one committed effect</h2><div v-for="x in data?.semantic_intents?.slice(0,8)||[]" :key="x.id" class="mt-3 flex justify-between rounded-lg border p-3 text-[9px]"><span><b>{{x.operation}}</b><small class="mt-1 block text-gray-400">{{x.semantic_key.slice(0,16)}}</small></span><span>{{x.state}}</span></div></article><article class="rounded-2xl border bg-gray-950 p-5 text-white"><span class="text-[9px] uppercase text-cyan-300">Transparency head</span><h2 class="mt-1 text-xl font-semibold">Tamper-evident evidence chain</h2><div v-for="x in data?.transparency?.slice(0,8)||[]" :key="x.sequence" class="mt-3 border-b border-gray-800 pb-3 text-[9px]"><div class="flex justify-between"><b>{{x.entry_type.replaceAll('_',' ')}}</b><span class="text-gray-500">#{{x.sequence}}</span></div><p class="mt-1 font-mono text-gray-500">{{x.entry_hash.slice(0,24)}}</p></div></article></section></div></main></template>
